const $=id=>document.getElementById(id); let currentGameData=null,requestInFlight=false,pendingTalkNpc=null,activeCategory=null,developerData=null,assetManifest={scenes:{}},lastFocusedElement=null;

function focusableElements(root){return [...root.querySelectorAll('button:not([disabled]), [href], input:not([disabled]), textarea:not([disabled]), select:not([disabled]), [tabindex]:not([tabindex="-1"])')].filter(x=>x.offsetParent!==null);}
function openModalAccessible(id,preferred){const modal=$(id);if(!modal)return;lastFocusedElement=document.activeElement;modal.classList.remove('hidden');requestAnimationFrame(()=>{const target=preferred?modal.querySelector(preferred):null;const first=target||focusableElements(modal)[0];first?.focus();});}
function closeModalAccessible(id){const modal=$(id);if(!modal)return;modal.classList.add('hidden');if(lastFocusedElement&&document.contains(lastFocusedElement))lastFocusedElement.focus();lastFocusedElement=null;}
function trapModalFocus(e){if(e.key!=='Tab')return;const modal=[...document.querySelectorAll('.modal:not(.hidden)')].pop();if(!modal)return;const items=focusableElements(modal);if(!items.length)return;const first=items[0],last=items[items.length-1];if(e.shiftKey&&document.activeElement===first){e.preventDefault();last.focus();}else if(!e.shiftKey&&document.activeElement===last){e.preventDefault();first.focus();}}

function slugifyLocation(v){return String(v||'').toLowerCase().replace(/[^a-z0-9]+/g,'_').replace(/^_|_$/g,'');}
function applyVisualState(data){
 const s=data.state||{}, w=s.weather||{}, key=slugifyLocation(data.location?.name), entry=assetManifest.scenes?.[key];
 const img=$('scene-art'), stage=$('scene-stage');
 document.body.dataset.season=String(s.season?.label||'').toLowerCase().replace(/\s+/g,'_');
 document.body.dataset.daypart=String(s.daypart||'').toLowerCase();
 const pressure=Number(s.horror?.pressure??s.horror_pressure??0);
 const horrorStage=pressure>=75?'severe':pressure>=50?'disturbed':pressure>=25?'uneasy':pressure>=8?'subtle':'pastoral';
 document.body.dataset.horrorStage=horrorStage;
 document.body.classList.toggle('atmosphere-uneasy',['uneasy','disturbed','severe'].includes(horrorStage));
 document.body.classList.toggle('atmosphere-acute',['disturbed','severe'].includes(horrorStage));
 document.body.style.setProperty('--horror-pressure',String(Math.max(0,Math.min(100,pressure))/100));
 if(entry?.default){img.src=entry.default;img.classList.remove('hidden');stage.classList.add('has-art');stage.style.setProperty('--scene-focal',entry.focal||'50% 50%');}
 else{img.removeAttribute('src');img.classList.add('hidden');stage.classList.remove('has-art');stage.style.removeProperty('--scene-focal');}
}
function presentationEffects(s){return new Set(s?.presentation_horror?.effects||[]);}
function applyInterfaceHorror(data){
 const fx=presentationEffects(data.state), body=document.body;
 body.classList.toggle('horror-theme-mismatch',fx.has('theme_mismatch'));
 body.classList.toggle('horror-text-dislocation',fx.has('text_dislocation'));
 body.classList.toggle('horror-text-repetition',fx.has('text_repetition'));
 body.classList.toggle('horror-portrait-shift',fx.has('portrait_tonal_shift'));
 body.classList.toggle('horror-map-contradiction',fx.has('map_contradiction'));
 body.classList.toggle('horror-journal-inconsistency',fx.has('journal_inconsistency'));
}
function displayOnlyJournalEcho(s){
 const fx=presentationEffects(s); if(!fx.has('journal_inconsistency'))return '';
 return `<div class="note-card presentation-contradiction" aria-label="An uncertain visual inconsistency"><strong>A line you remember writing is not where you expect it.</strong><p>You cannot tell whether the page changed or your attention did.</p></div>`;
}

async function loadAssetManifest(){try{const r=await fetch('/static/assets/asset_manifest.json',{cache:'no-store'});if(r.ok)assetManifest=await r.json();}catch(e){console.warn('Asset manifest fallback active',e);}}

const ACTION_CATEGORIES=[['people','Talk',['story','talk','free_talk','choice','social']],['care','Care',['life','home']],['work','Work',['job','economy']],['explore','Explore',['observe','investigate']],['travel','Travel',['travel']]];
function escapeHtml(v){return String(v??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[c]));}
function currencyMarkup(value){return `<span class="currency"><span class="currency-mark">฿</span>${escapeHtml(value??0)}</span>`;}
function playerText(v){return escapeHtml(v||'').replace(/(?:Br\s+|¤|฿|B)(\d+)/g,(_,n)=>currencyMarkup(n));}
function diagnosticLineMarkup(text){return escapeHtml(text||'').replace(/(?:Br\s+|¤|฿|B)(\d+)/g,(_,n)=>currencyMarkup(n));}
function devMode(){const q=new URLSearchParams(location.search);if(q.get('dev')==='1')sessionStorage.setItem('bellwether_dev','1');if(q.get('dev')==='0')sessionStorage.removeItem('bellwether_dev');return sessionStorage.getItem('bellwether_dev')==='1';}
function render(data){currentGameData=data;const s=data.state,w=s.weather||{};$('location').textContent=data.location.name;$('scene-title-overlay').textContent=data.location.name;const season=s.season?.label||'Season unknown';$('status').innerHTML=`Day ${s.day} · ${s.time} · ${season} · ${escapeHtml(w.label)} · ${w.temperature_c}°C · ${currencyMarkup(s.money)}`; const ps=s.player_status_overview||s.player_status||{}; $('player-vitals').innerHTML=`<button onclick="openPanel('status')"><b>Health</b> ${Math.round(ps.health??100)} · <b>Hunger</b> ${Math.round(ps.hunger??0)} · <b>Energy</b> ${Math.round(ps.energy??100)}</button>`;document.body.dataset.weather=w.state||'clear';document.body.dataset.daypart=s.daypart||'';applyVisualState(data);applyInterfaceHorror(data);
const effect=data.world_context?.weather_effect||'';$('weather-impact').textContent=effect;$('weather-impact').style.display=effect?'block':'none';const placeText=data.location?.description||'Nothing unusual demands your attention.';$('environment-line-overlay').textContent=effect||placeText;
const rawMsgs=s.new_messages||[], ex=data.conversation_exchange, exchangeMsgs=ex?[{speaker:'You',text:ex.player},{speaker:ex.npc_name,text:ex.npc}]:[], dialogueMsgs=exchangeMsgs.length?exchangeMsgs:rawMsgs.filter(l=>!/^narrator$/i.test(l.speaker)), narratorMsgs=rawMsgs.filter(l=>/^narrator$/i.test(l.speaker));$('dialogue').innerHTML=dialogueMsgs.length?dialogueMsgs.map(l=>{const kind=/^bellwether$/i.test(l.speaker)?'world-line':'dialogue-line';return `<p class="line ${kind}"><span class="speaker">${escapeHtml(l.speaker)}</span><br>${playerText(l.text)}</p>`;}).join(''):'<p class="line quiet-line">The moment settles. Choose what to do next.</p>';$('dialogue').scrollTop=$('dialogue').scrollHeight;const ns=$('narrator-strip');if(ns){if(narratorMsgs.length){ns.innerHTML=`<span class="narrator-mark">Narrator</span><span>${narratorMsgs.map(l=>playerText(l.text)).join(' ')}</span>`;ns.classList.remove('hidden');}else{ns.innerHTML='';ns.classList.add('hidden');}}
renderActions(data.actions||[]);renderContext(data);
startPacingMonitor();}
function actionButton(a){const b=document.createElement('button');b.textContent=a.label;b.onclick=()=>a.kind==='free_talk'?openTalk(a):act(a.id);return b;}
function categoryFor(a){if(a.category){if(a.category==='work')return 'work';if(a.category==='home'||a.category==='activities')return 'care';if(a.category==='investigate')return 'explore';return a.category;}for(const [id,,kinds] of ACTION_CATEGORIES)if(kinds.includes(a.kind))return id;return 'care';}
function renderActions(actions){const groups={};ACTION_CATEGORIES.forEach(([id])=>groups[id]=[]);
const urgent=actions.filter(a=>a.kind==='choice'||/treat|shelter|begin another run/i.test(a.label)); const social=actions.filter(a=>a.kind==='talk'||a.kind==='free_talk'); const quick=[...urgent,...social].filter((a,i,x)=>x.findIndex(y=>y.id===a.id)===i).slice(0,3);const quickIds=new Set(quick.map(a=>a.id));actions.filter(a=>!quickIds.has(a.id)).forEach(a=>groups[categoryFor(a)].push(a));
$('quick-actions').innerHTML='';quick.forEach(a=>$('quick-actions').appendChild(actionButton(a)));
$('action-dock').innerHTML='';ACTION_CATEGORIES.forEach(([id,label])=>{const b=document.createElement('button');b.textContent=`${label}${groups[id].length?` · ${groups[id].length}`:''}`;b.disabled=!groups[id].length;b.onclick=()=>openActionTray(id,label,groups[id]);$('action-dock').appendChild(b);});
if(activeCategory){const meta=ACTION_CATEGORIES.find(x=>x[0]===activeCategory);if(meta)openActionTray(meta[0],meta[1],groups[meta[0]]);}}
function openActionTray(id,label,items){activeCategory=id;$('tray-title').textContent=label;const host=$('tray-actions');host.innerHTML='';const groups={};items.forEach(a=>(groups[a.intent||'ordinary_life']??=[]).push(a));Object.entries(groups).forEach(([intent,xs])=>{if(Object.keys(groups).length>1){const h=document.createElement('div');h.className='action-intent-label';h.textContent=humanLabel(intent);host.appendChild(h);}xs.forEach(a=>host.appendChild(actionButton(a)));});$('action-tray').classList.remove('hidden');}
function closeActionTray(){activeCategory=null;$('action-tray').classList.add('hidden');}
function renderContext(data){const s=data.state;const all=[...(s.quests?.main||[]),...(s.quests?.side||[])];const q=all.find(x=>!x.done);$('current-objective').innerHTML=q?`<strong>${escapeHtml(q.title)}</strong><p>${escapeHtml(q.objective)}</p>`:'<small>No urgent thread. The day is yours.</small>';
const people=(data.present?.npcs||[]).map(n=>`<button class="presence npc-presence compact-person" data-npc-id="${escapeHtml(n.id||'')}" data-npc-name="${escapeHtml(n.name)}" data-npc-activity="${escapeHtml(n.activity||'')}"><span><strong>${escapeHtml(n.name)}</strong><small>${escapeHtml(n.activity||'Nearby')}</small></span><span aria-hidden="true">›</span></button>`);$('presence').innerHTML=people.join('')||'<small>The immediate area is quiet.</small>';$('presence').querySelectorAll('[data-npc-name]').forEach(b=>b.onclick=()=>openNpcPanel(b.dataset.npcId,b.dataset.npcName,b.dataset.npcActivity));
const danger=s.danger||{},job=s.employment||s.jobs||{};$('immediate-state').innerHTML=`<div>${escapeHtml(data.world_context?.weather_effect||'Conditions are ordinary.')}</div>${danger.injuries?.length?`<div class="warning">Injured · ${danger.injuries.length} condition(s)</div>`:''}${job.current_job?`<div>Work: ${escapeHtml(job.current_job)}</div>`:''}`; const sides=(s.quests?.side||[]); const activeSides=sides.filter(x=>!x.done), recentDone=sides.filter(x=>x.done).slice(-3); $('side-stories').innerHTML=[...activeSides,...recentDone].map(x=>`<div class="side-story ${x.done?'done':''}"><strong>${escapeHtml(x.title)}</strong><small>${x.done?'Completed':escapeHtml(x.status==='in_progress'?'In progress · '+x.objective:x.objective)}</small></div>`).join('')||'<small>No side stories yet.</small>'; const seenRecent=new Set(),hist=(s.history||[]).slice().reverse().filter(x=>!/^Another small errand|^Footsteps and wheels|^A delivery has been made/.test(x.text||'')).filter(x=>{const k=`${x.speaker}|${x.text}`;if(seenRecent.has(k))return false;seenRecent.add(k);return true;}).slice(0,3); $('recent-events').innerHTML=hist.map(x=>`<div class="recent-event">${escapeHtml(x.text)}</div>`).join('')||'<small>Your days here are only beginning.</small>';}
function npcActionsFor(id,name){return (currentGameData?.actions||[]).filter(a=>(id&&a.npc_id===id)||(!id&&a.npc_name===name));}
function openNpcPanel(id,name,activity){const key=slugifyLocation(id||name),entry=assetManifest.characters?.[key]||assetManifest.characters?.[slugifyLocation(name)],src=entry?.neutral||entry?.default||'';const rel=currentGameData?.state?.relationships?.[id]||{};const actions=npcActionsFor(id,name);$('npc-panel-title').textContent=name;$('npc-panel-content').innerHTML=`<div class="npc-focus">${src?`<img src="${escapeHtml(src)}" alt="Portrait of ${escapeHtml(name)}">`:''}<div><h3>${escapeHtml(name)}</h3><p class="npc-current-activity">${escapeHtml(activity||'Nearby')}</p><p>${Object.keys(rel).length?relationshipDescription(rel):'You are still forming an impression of each other.'}</p></div></div><div class="npc-panel-actions">${actions.length?actions.map(a=>`<button data-npc-action="${escapeHtml(a.id)}" data-kind="${escapeHtml(a.kind)}">${escapeHtml(a.label)}</button>`).join(''):'<p><small>No special interaction is available right now.</small></p>'}</div>`;$('npc-panel-content').querySelectorAll('[data-npc-action]').forEach(b=>b.onclick=()=>{closeNpcPanel();const a=actions.find(x=>x.id===b.dataset.npcAction);a?.kind==='free_talk'?openTalk(a):act(b.dataset.npcAction);});openModalAccessible('npc-modal');}
function closeNpcPanel(){closeModalAccessible('npc-modal');}
function closeNpcPanelFromBackdrop(e){if(e.target.id==='npc-modal')closeNpcPanel();}

function displayText(value){if(value===null||value===undefined)return '';if(typeof value==='string'||typeof value==='number'||typeof value==='boolean')return String(value);if(Array.isArray(value))return value.map(displayText).filter(Boolean).join(' · ');if(typeof value==='object')return displayText(value.text||value.summary||value.label||value.description||value.reason||Object.values(value).filter(v=>typeof v==='string')[0]||'');return '';}
function relationshipNpcName(s,id){return s.npcs?.[id]?.name||s.population?.residents?.[id]?.name||String(id).replace(/_/g,' ').replace(/\b\w/g,c=>c.toUpperCase());}

function relationshipDescription(r){const f=Number(r.familiarity||0),a=Number(r.affinity||0),t=Number(r.trust||0);const familiarity=f>=8?'Well known':f>=4?'A familiar face':'New acquaintance';const warmth=a>=6?'Warm toward you':a>=2?'Comfortable around you':a<0?'Uneasy around you':'Still forming an impression';const trust=t>=6?'Trusts you':t>=2?'Some trust is forming':t<0?'Guarded':'Trust remains cautious';return `${familiarity}<br><small>${warmth} · ${trust}</small>`;}
function availableActions(prefix){return (currentGameData?.actions||[]).filter(a=>a.id.startsWith(prefix));}
function panelActionButtons(items){return items.map(a=>`<button class="panel-action" data-action-id="${escapeHtml(a.id)}">${escapeHtml(a.label)}</button>`).join('');}
function cropName(id){return String(id||'').replace(/_/g,' ').replace(/\b\w/g,c=>c.toUpperCase());}
function gardenHtml(s){const g=s.player_activities?.garden||{},plots=g.plots||[];const plotHtml=plots.map((p,i)=>{if(!p)return `<div class="garden-plot empty"><strong>Plot ${i+1}</strong><span>Empty bed</span></div>`;const ratio=Math.max(0,Math.min(100,Math.round(100*Number(p.growth||0)/Math.max(1,Number(p.growth_required||1)))));return `<div class="garden-plot"><strong>Plot ${i+1} · ${escapeHtml(cropName(p.crop_id))}</strong><span>${ratio>=100?'Ready to harvest':ratio>=70?'Maturing':ratio>=30?'Growing':ratio>0?'Seedling':'Sown'} · ${ratio}%</span><div class="meter"><i style="width:${ratio}%"></i></div><small>Health ${Math.round(Number(p.health??100))}%</small></div>`;}).join('');const seeds=Object.entries(g.seed_stock||{}).filter(([,n])=>Number(n)>0).map(([k,n])=>`${cropName(k)} ×${n}`).join(' · ')||'No seeds stored';const harvest=Object.entries(g.harvest_store||{}).filter(([,n])=>Number(n)>0).map(([k,n])=>`${cropName(k)} ×${n}`).join(' · ')||'Nothing harvested yet';return `<div class="garden-overview"><div class="stat-grid"><div><b>Soil</b><span>${g.soil_prepared?'Prepared':'Unprepared'} · ${Math.round(Number(g.soil_condition||0))}%</span></div><div><b>Moisture</b><span>${Math.round(Number(g.moisture||0))}%</span></div><div><b>Weeds</b><span>${Math.round(Number(g.weeds||0))}%</span></div><div><b>Gardening skill</b><span>${Number(s.player_activities?.skills?.gardening||0)}</span></div></div><div class="garden-plots">${plotHtml}</div><div class="store-line"><b>Seed box</b><span>${escapeHtml(seeds)}</span></div><div class="store-line"><b>Harvest basket</b><span>${escapeHtml(harvest)}</span></div><div class="panel-actions">${panelActionButtons(availableActions('garden:'))}</div></div>`;}
function cookingHtml(s){const c=s.content_progression?.cooking||{},life=s.life_simulation_overview||s.life_simulation||{},pantry=life.pantry||{},preserves=Object.entries(pantry.preserves||{}).filter(([,n])=>Number(n)>0).map(([k,n])=>`${humanLabel(k)} ×${n}`).join(' · ')||'No preserves stored',known=c.recipes_known||[];const names={radish_toast:'Radish and butter toast',garden_salad:'Garden salad',carrot_soup:'Carrot soup',bean_stew:'Broad bean stew'};const available=new Set(availableActions('content:cook:').map(a=>a.id.split(':').pop()));return `<div class="recipe-grid">${known.map(id=>`<div class="recipe-card ${available.has(id)?'available':''}"><strong>${escapeHtml(names[id]||cropName(id))}</strong><span>${available.has(id)?'Ingredients ready':'Ingredients needed'}</span></div>`).join('')}</div><p>Meals cooked: <strong>${Number(c.meals_cooked||0)}</strong> · Cooking skill: <strong>${Number(s.player_activities?.skills?.cooking||0)}</strong></p><div class="store-line"><b>Preserves</b><span>${escapeHtml(preserves)}</span></div><p>Meals shared: <strong>${Number(pantry.meals_shared||0)}</strong></p><div class="panel-actions">${panelActionButtons([...availableActions('content:cook:'),...availableActions('lifesim:preserve:'),...availableActions('lifesim:share_meal')])}</div>`;}
function animalsHtml(s){const rt=s.cottage_animals_overview||s.cottage_animals||{},animals=rt.animals||[],products=Object.entries(rt.products||{}).filter(([,n])=>Number(n)>0).map(([k,n])=>`${humanLabel(k)} ×${n}`).join(' · ')||'Nothing stored';const cards=animals.map(a=>`<div class="animal-card"><strong>${escapeHtml(a.name)}</strong><span>${humanLabel(a.species)} · Health ${Math.round(a.health)} · Trust ${Math.round(a.trust)}</span><small>${a.hunger>=70?'Very hungry':a.hunger>=40?'Hungry':'Fed'} · ${humanLabel(a.intention||'rest')}</small></div>`).join('')||'<p>No animals live at the cottage yet. A small coop is the first step.</p>';return `<div class="animal-overview"><div class="stat-grid"><div><b>Feed</b><span>${Number(rt.feed||0)} portions</span></div><div><b>Coop</b><span>${rt.shelters?.coop?'Ready':'Not built'}</span></div><div><b>Goat shelter</b><span>${rt.shelters?.goat_shed?'Ready':'Not built'}</span></div></div><div class="animal-grid">${cards}</div><div class="store-line"><b>Animal produce</b><span>${escapeHtml(products)}</span></div><div class="panel-actions">${panelActionButtons(availableActions('animals:'))}</div></div>`;}
function homeHtml(s){const rest=s.content_progression?.home_restoration||{},done=new Set(rest.completed||[]),repairs={kitchen_stove:'Old kitchen stove',bedroom_window:'Bedroom window',garden_gate:'Garden gate'};return `<div class="home-hero"><img src="/static/assets/scenes/cottage_interior/cottage_interior.png" alt="Ashcroft Cottage interior"><div><h3>Ashcroft Cottage</h3><p>${Number(s.player_status?.cottage?.condition??100)>=75?'Sound and lived-in':Number(s.player_status?.cottage?.condition??100)>=50?'Worn but serviceable':'In need of attention'} · ${Number(s.player_activities?.garden?.plots?.filter(Boolean).length||0)} garden plots in use</p></div></div><div class="home-tabs"><button data-home-view="garden">Garden</button><button data-home-view="cooking">Cooking</button><button data-home-view="restoration">Restoration</button><button data-home-view="animals">Animals</button></div><div id="home-detail"><h3>Garden</h3>${gardenHtml(s)}</div><template id="home-garden-template">${gardenHtml(s)}</template><template id="home-cooking-template">${cookingHtml(s)}</template><template id="home-animals-template">${animalsHtml(s)}</template><template id="home-restoration-template"><div class="repair-grid">${Object.entries(repairs).map(([id,name])=>`<div class="repair-card ${done.has(id)?'done':''}"><strong>${escapeHtml(name)}</strong><span>${done.has(id)?'Completed':'Still needs attention'}</span></div>`).join('')}</div><p>Repair supplies: <strong>${Number(s.economy?.household?.repair_supplies||0)}</strong></p><div class="panel-actions">${panelActionButtons(availableActions('content:repair:'))}</div></template>`;}
